async def seed_exercises(db: AsyncSession) -> None:
    result = await db.execute(select(func.count()).select_from(Exercise).where(Exercise.is_custom == False))  # noqa: E712
    count = result.scalar() or 0
    if count > 0:
        return

    exercises = [Exercise(**data) for data in EXERCISES]
    db.add_all(exercises)
    await db.commit()
